            useStyles: true,
        };

        const workbook = new Exceljs.stream.xlsx.WorkbookWriter(options);
        const sheet = workbook.addWorksheet("reports");
       // process here (committing every row I create)
       // then committing the unique sheet I need
       sheet.commit();
       await workbook.commit();
```
Please help

comments.body:
I ran into a similar issue, the same code was producing a valid xlsx file on v15.x but a corrupted file on v16.x on one of my project.
It was working fine on another project under v16 with exactly the same versions installed.
I tested the same code on a freshly installed project with only one dependency to exceljs and  it was working fine under v16.x.

`Removing the yarn.lock and installing again fixed the issue on the project that was failing.`

My guess is that this issue is caused by the version resolution of a dependency of exceljs **dependencies** (no a direct dependency). Don't know exactly which one though. One related to streams or compression/zip probably.

Hope this helps.

The code used for reference:
```typescript
import { createWriteStream } from 'fs';

import Excel from 'exceljs';

(async () => {
  const stream = createWriteStream('test.xlsx');

  const workbook = new Excel.stream.xlsx.WorkbookWriter({ stream });
  const sheet = workbook.addWorksheet('Users');
  sheet.columns = [
    {
      "header": "First name",
      "key": "firstName"
    }
  ] as any;
  sheet.addRow({ "firstName": "John" }).commit();

  sheet.commit();
  await workbook.commit();
  await new Promise(stream.on.bind(stream, 'finish'));
})();
```

